import math

def interval_z(n, sample_mean, sigma, alfa):
    z = math.sqrt(2.0) * _erfinv(2.0 * (1 - alfa) - 1.0)
    margine = z * sigma / math.sqrt(n)
    return (sample_mean - margine, sample_mean + margine)

def _erfinv(y):
    x = 0.0
    for _ in range(100):
        x = x - (math.erf(x) - y) / (2 / math.sqrt(math.pi) * math.exp(-x * x))
    return x

lo, hi = interval_z(25, 67.53, 10, 0.1)
print(f"[1] {lo:.5f} {hi:.5f}")
